import{z as e}from"zod";export const VoiceDesignRequestSchema=e.object({prompt:e.string().min(1),preview_text:e.string().default(""),voice_id:e.string().min(1),aigc_watermark:e.boolean().default(!1)}),VoiceCloneRequestSchema=e.object({file_id:e.number().int(),voice_id:e.string().min(1),clone_prompt:e.object({prompt_audio:e.number().int(),prompt_text:e.string()}).optional(),text:e.string().optional(),model:e.string().default("speech-2.8-hd"),language_boost:e.string().default("auto"),need_noise_reduction:e.boolean().default(!1),need_volume_normalization:e.boolean().default(!1),aigc_watermark:e.boolean().default(!1)}),KlingCustomVoiceRequestSchema=e.object({voice_name:e.string().min(1),voice_url:e.string().optional(),video_id:e.string().optional(),callback_url:e.string().optional(),external_task_id:e.string().optional()}),VoiceInfoSchema=e.object({voice_id:e.string(),voice_name:e.string().optional(),status:e.string().optional(),provider:e.enum(["minimax","kling"])}),CustomVoiceSchema=e.object({voiceId:e.string().min(1),name:e.string().min(1),provider:e.enum(["minimax","kling"]),source:e.enum(["design","clone"]),prompt:e.string().default(""),createdAt:e.string().default("")});
